import {
  forwardRef,
  type CSSProperties,
  type ElementType,
  type ReactNode,
} from 'react';
import { cn, vc } from '../../utils/cn';
import styles from './Typography.module.css';

export type TypographyVariant =
  | 'h1'
  | 'h2'
  | 'h3'
  | 'h4'
  | 'h5'
  | 'h6'
  | 'body1'
  | 'body2'
  | 'caption'
  | 'overline';

export type TypographyWeight = 'normal' | 'medium' | 'semibold' | 'bold';
export type TypographyAlign = 'left' | 'center' | 'right';

const variantToElement: Record<TypographyVariant, ElementType> = {
  h1: 'h1',
  h2: 'h2',
  h3: 'h3',
  h4: 'h4',
  h5: 'h5',
  h6: 'h6',
  body1: 'p',
  body2: 'p',
  caption: 'span',
  overline: 'span',
};

export interface TypographyProps {
  variant?: TypographyVariant;
  as?: ElementType;
  color?: string;
  align?: TypographyAlign;
  weight?: TypographyWeight;
  truncate?: boolean;
  maxLines?: number;
  className?: string;
  style?: CSSProperties;
  children?: ReactNode;
  'data-testid'?: string;
}

export const Typography = forwardRef<HTMLElement, TypographyProps>(
  function Typography(
    {
      variant = 'body1',
      as,
      color,
      align,
      weight,
      truncate,
      maxLines,
      className,
      style,
      children,
      'data-testid': dataTestId = 'tatva-typography',
    },
    ref,
  ) {
    const Component = (as ?? variantToElement[variant]) as ElementType;
    const combinedStyle: CSSProperties = {
      ...(color
        ? { color: color.startsWith('--') ? `var(${color})` : color }
        : {}),
      ...(align ? { textAlign: align } : {}),
      ...(maxLines
        ? {
            display: '-webkit-box',
            WebkitBoxOrient: 'vertical',
            WebkitLineClamp: maxLines,
            overflow: 'hidden',
          }
        : {}),
      ...style,
    };
    return (
      <Component
        ref={ref}
        data-testid={dataTestId}
        className={cn(
          styles.base,
          vc(styles, 'variant', variant),
          weight && vc(styles, 'weight', weight),
          truncate && styles.truncate,
          className,
        )}
        style={combinedStyle}
      >
        {children}
      </Component>
    );
  },
);

.base {
  font-family: var(--tatva-font-family);
  color: var(--tatva-color-fg);
  margin: 0;
}

.variantH1 {
  font-size: var(--tatva-font-size-4xl);
  font-weight: var(--tatva-font-weight-bold);
  line-height: var(--tatva-line-height-tight);
  letter-spacing: -0.02em;
}
.variantH2 {
  font-size: var(--tatva-font-size-3xl);
  font-weight: var(--tatva-font-weight-bold);
  line-height: var(--tatva-line-height-tight);
  letter-spacing: -0.01em;
}
.variantH3 {
  font-size: var(--tatva-font-size-2xl);
  font-weight: var(--tatva-font-weight-semibold);
  line-height: var(--tatva-line-height-tight);
}
.variantH4 {
  font-size: var(--tatva-font-size-xl);
  font-weight: var(--tatva-font-weight-semibold);
  line-height: var(--tatva-line-height-tight);
}
.variantH5 {
  font-size: var(--tatva-font-size-lg);
  font-weight: var(--tatva-font-weight-semibold);
  line-height: var(--tatva-line-height-normal);
}
.variantH6 {
  font-size: var(--tatva-font-size-md);
  font-weight: var(--tatva-font-weight-semibold);
  line-height: var(--tatva-line-height-normal);
}
.variantBody1 {
  font-size: var(--tatva-font-size-md);
  line-height: var(--tatva-line-height-normal);
}
.variantBody2 {
  font-size: var(--tatva-font-size-sm);
  line-height: var(--tatva-line-height-normal);
}
.variantCaption {
  font-size: var(--tatva-font-size-xs);
  color: var(--tatva-color-fg-muted);
  line-height: var(--tatva-line-height-normal);
}
.variantOverline {
  font-size: var(--tatva-font-size-xs);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--tatva-color-fg-muted);
}

.weightNormal {
  font-weight: var(--tatva-font-weight-normal);
}
.weightMedium {
  font-weight: var(--tatva-font-weight-medium);
}
.weightSemibold {
  font-weight: var(--tatva-font-weight-semibold);
}
.weightBold {
  font-weight: var(--tatva-font-weight-bold);
}

.truncate {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

export { Typography } from './Typography';
export type {
  TypographyProps,
  TypographyVariant,
  TypographyWeight,
  TypographyAlign,
} from './Typography';
